265	  checkFields(colDefs: ColDef[]){
266	    const statusHeader = colDefs.find(header => header.field && header.field.toLowerCase() === 'status');
267	    if (statusHeader) {
268	      statusHeader.cellEditor = "agSelectCellEditor";
269	      statusHeader.cellEditorParams = {
270	        values: ['Active', 'Inactive']
271	      };
272	      statusHeader.valueFormatter = params => {
273	        return params.value || '';
274	      };
275	    }
276	
277	    //Role dropdown for 'user' type view
278	    if (this.selectedUserType?.title.toLowerCase() === 'user') {
279	      const roleHeader = colDefs.find(header => header.field && header.field.toLowerCase() === 'role');
280	      if (roleHeader) {
281	        roleHeader.cellEditor = "agSelectCellEditor";
282	        roleHeader.cellEditorParams = {
283	          values: ['admin', 'sales', 'designer', 'production', 'sourcing_manager']
284	        };
285	      }
286	    }
