289	  private buildImpersonateColDef(targetType: 'user' | 'vendor' | 'factory' = 'user'): ColDef {
290	    const svc = this.impersonationService;
291	    return {
292	      headerName: '',
293	      width: 135,
294	      minWidth: 135,
295	      maxWidth: 135,
296	      suppressSizeToFit: true,
297	      editable: false,
298	      sortable: false,
299	      filter: false,
300	      floatingFilter: false,
301	      pinned: 'left' as any,
302	      cellRenderer: (params: any) => {
303	        const userId = params.data?.id ?? params.data?.['User ID #'] ?? params.data?.vendor_id ?? params.data?.Id;
304	        if (!userId) return null;
305	        const displayName = [
306	          params.data?.name ?? params.data?.['First Name'],
307	          params.data?.lastname ?? params.data?.['Last Name'],
308	        ].filter(Boolean).join(' ')
309	          || params.data?.factory_nickname
310	          || params.data?.Factory_nickname
311	          || params.data?.factory_name
312	          || params.data?.Factory_name
313	          || params.data?.company_nickname
314	          || params.data?.['Company Nickname']
315	          || params.data?.Email
316	          || params.data?.email
317	          || '';
318	        const btn = document.createElement('button');
319	        btn.textContent = 'Impersonate';
320	        btn.title = `View app as ${displayName}`;
321	        btn.style.cssText = [
322	          'font-size:11px',
323	          'padding:2px 10px',
324	          'cursor:pointer',
325	          'border:1px solid #e65100',
326	          'color:#e65100',
327	          'background:transparent',
328	          'border-radius:4px',
329	          'white-space:nowrap',
330	        ].join(';');
331	        btn.addEventListener('click', () => svc.startImpersonation(Number(userId), targetType));
332	        return btn;
333	      },
334	    };
335	  }
