337	  async onSaveNewView(value) {
338	    this.viewLayouts.push({ layout_name: value });
339	    const allState = this.gridColumnApi.getColumnState();
340	    const orderAndVisibilityState = allState.map((state, index) => ({
341	      colId: state.colId,
342	      hide: state.hide,
343	      pinned: state.pinned,
344	      width: state.width,
345	      order: index,
346	      layout_name: value,
347	      col_id: (function (data) {
348	        for (var i = 0; i < data.length; i++) {
349	          if (data[i].field == state.colId) {
350	            return data[i].col_id
351	          }
352	        }
353	      })(this.colHeaders),
354	      grid_id: this.selectedUserType.value
355	    }));
356	    try {
357	      const data: any = await this.itemService.saveGridLayout(orderAndVisibilityState).toPromise();
358	      if (data) {
359	        this._snakcbar.open(`Current view was saved successfully.`, 'close');
360	      }
361	    } catch (err) {
362	      console.error('[ManageUsersComponent] saveGridLayout failed:', err);
363	    }
364	  }
