375	  async onSaveLayout(selectedView) {
376	    if (selectedView.layout_name != 'Default' && selectedView.layout_name != null) {
377	      const allState = this.gridColumnApi.getColumnState();
378	      const orderAndVisibilityState = allState.map((state, index) => ({
379	        colId: state.colId,
380	        hide: state.hide,
381	        pinned: state.pinned,
382	        width: state.width,
383	        order: index,
384	        layout_name: selectedView.layout_name,
385	        col_id: (function (data) {
386	          for (var i = 0; i < data.length; i++) {
387	            if (data[i].field == state.colId) {
388	              return data[i].col_id
389	            }
390	          }
391	        })(this.colHeaders),
392	        grid_id: this.selectedUserType.value
393	      }));
394	      try {
395	        await this.itemService.saveGridLayout(orderAndVisibilityState).toPromise();
396	        this._snakcbar.open(`Current view was saved successfully.`, 'close');
397	      } catch (err) {
398	        console.error('[ManageUsersComponent] saveGridLayout (onSaveLayout) failed:', err);
399	      }
400	    } else {
401	      this._snakcbar.open(`You can't save on Default view. Please select a diffrent view or create a new one.`, 'close')
402	    }
