428	  private reloadData(): void {
429	    const isFactoriesView =
430	      this.selectedUserType.value === 'manage_factories';
431	  
432	    if (isFactoriesView) {
433	      this.loadFactoriesView();
434	    } else {
435	      this.loadUsersView();
