439	  private loadUsersView(): void {
440	    this.gridApi?.setGridOption('paginationPageSize', 15);
441	    const gridIdForApi = this.selectedUserType.value;
442	
443	    forkJoin({
444	      data: this.itemService.getAllUsers({
445	        userType: this.selectedUserType,
446	        userStatus: this.selectedUserStatus,
447	        signUpStatus: this.selectedSignUpStatus
448	      }),
449	      viewState: this.itemService.getSelectedGridView({
450	        layout_name: 'Default',
451	        grid_id: gridIdForApi
452	      })
453	    }).subscribe(({ data, viewState }) => {
454	  
455	      const colHeaders = [...USER_COLUMN_HEADERS_CONFIG.columnDefs];
456	  
457	      if (colHeaders?.length) {
458	        colHeaders.forEach(col => {
459	          if (col.colId === 'pic') {
460	            // Render the effective avatar (uploaded photo, else cached M365/Graph
461	            // photo) as a round image; fall back to the generic user icon.
462	            col.cellRenderer = (params: any) => {
463	              const url = params.value || '/assets/img/user/user-icon.png';
464	              return `<img src="${url}" alt="avatar" referrerpolicy="no-referrer" ` +
465	                `style="width:32px;height:32px;border-radius:50%;object-fit:cover;vertical-align:middle;" ` +
466	                `onerror="this.onerror=null;this.src='/assets/img/user/user-icon.png';" />`;
467	            };
468	            col.cellStyle = { 'text-align': 'center' };
469	            col.editable = false;
470	          }
471	        });
472	  
473	        this.colHeaders = colHeaders;
474	        this.columnDefs = [this.buildImpersonateColDef(), ...colHeaders];
475	        this.checkFields(this.columnDefs);
476	      } else {
477	        this.colHeaders = [];
478	        this.columnDefs = [this.buildImpersonateColDef()];
479	      }
480	  
481	      this.setGridData(data as any, viewState as any);
482	      
483	      // Decrement loader for initial load only
484	      if (this.isInitialLoad) {
485	        this.isInitialLoad = false;
486	        this.loaderService.decrement();
487	      }
488	    }, (error) => {
489	      // Decrement loader on error for initial load
490	      if (this.isInitialLoad) {
491	        this.isInitialLoad = false;
492	        this.loaderService.decrement();
493	      }
494	      this.setGridLoading(false);
495	    });
496	  }
