498	  private formatNumber(value: number | string): string {
499	    const num = Number(value);
500	    if (isNaN(num)) {
501	      return '';
502	    }
503	  
504	    return num
505	      .toFixed(2)
506	      .replace(/\B(?=(\d{3})+(?!\d))/g, ',');
507	  }
508	  
509	  private formatDate(input: string | null | undefined): string {
510	    if (!input) {
511	      return '';
512	    }
513	  
514	    if (!input.includes('-')) {
515	      return input;
516	    }
517	  
518	    const [year, month, day] = input.split('-');
519	    return `${month}/${day}/${year}`;
520	  }
