522	  private loadFactoriesView(): void {
523	    this.gridApi?.setGridOption('paginationPageSize', 100);
524	    forkJoin({
525	    factoryHeaders: this.itemService.getGridHeader({ grid_id: 'manage_factories' }),
526	      vendorHeaders: this.itemService.getGridHeader({ grid_id: 'manage_vendors' }),
527	      data: this.itemService.getAllUsers({
528	        userType: this.selectedUserType,
529	        userStatus: this.selectedUserStatus,
530	        signUpStatus: this.selectedSignUpStatus
531	      }),
532	      viewState: this.itemService.getSelectedGridView({
533	        layout_name: 'Default',
534	        grid_id: 'manage_factories'
535	      })
536	    }).subscribe(({ vendorHeaders, data, viewState }) => {
537	
538	     const factoryHeaders = [...FACTORIES_COLUMN_HEADERS_CONFIG.columnDefs]; 
539	  
540	      if (factoryHeaders?.length) {
541	        factoryHeaders[0].cellRenderer = 'agGroupCellRenderer';
542	      }
543	  
544	      this.checkFields(factoryHeaders);
545	      this.columnDefs = [this.buildImpersonateColDef('factory'), ...factoryHeaders];
546	  
547	      this.checkFields(vendorHeaders as any);
548	      const vendorColumnDefs = [this.buildImpersonateColDef('vendor'), ...(vendorHeaders as ColDef[])];
549	  
550	      this.gridApi.setGridOption('masterDetail', true);
551	
552	
553	      this.gridApi.setGridOption('detailCellRendererParams', {
554	        
555	        detailGridOptions: {
556	          columnDefs: vendorColumnDefs,
557	          defaultColDef: {
558	            detailRowAutoHeight: true,
559	            suppressRowTransform: true,
560	            flex: 1,
561	            resizable: true,
562	            sortable: true,
563	            editable: true
564	          },
565	          onCellValueChanged: this.onDetailCellValueChanged.bind(this)
566	        },
567	        getDetailRowData: (params) => {
568	          params.successCallback(params.data.Vendors || []);
569	        }
570	      })
571	  
572	      this.setGridData(data as any, viewState as any);
573	      
574	      // Decrement loader for initial load only
575	      if (this.isInitialLoad) {
576	        this.isInitialLoad = false;
577	        this.loaderService.decrement();
578	      }
579	    }, (error) => {
580	      // Decrement loader on error for initial load
581	      if (this.isInitialLoad) {
582	        this.isInitialLoad = false;
583	        this.loaderService.decrement();
584	      }
585	      this.setGridLoading(false);
586	    })
587	  }
