input.new_string:
// Debug globals (window['dialog'/'_snackBar'/'router'/'itemService'/'currentUrl'])
// removed (A4): security smell, and nothing reads them in this page's context
// (dialog/router/snackBar/itemService/currentUrl are read only by RFQ/licensing/
// standardized/prod_tracking components, which each set their own).
// window['togglePageToolbar'] is intentionally KEPT: the Vex toolbar component
// (src/@vex/layout/toolbar/toolbar.component.ts) reads it to drive the toolbar
// toggle button while this page is active.
window['togglePageToolbar'] = this.toggleToolbarVisibility.bind(this);
let url = this.router.url;
let urlArray = url.split('/');
this.currentUrl = urlArray[urlArray.length - 1];

role: any
detailRowHeight = 200;

// A2: defense-in-depth UI gating for admin-only toolbar actions. The route is
// already protected by RoleGuard; this prevents the action buttons from even
// rendering for non-admins if the guard is ever bypassed/misconfigured.
// `role` is populated asynchronously in loadUserRole(); until then this is false
// so admin actions don't flash for non-admins.
get isAdmin(): boolean {
  return this.role === 'admin';
}

